from lxml import etree

def process_soap_request(soap_request):
    # Define the DTD for validation
    dtd_string = """
    <!ELEMENT Envelope (Header?, Body)>
    <!ELEMENT Header (#PCDATA)>
    <!ELEMENT Body (#PCDATA)>
    """
    dtd = etree.DTD(etree.fromstring(dtd_string))

    # Parse the SOAP request
    try:
        root = etree.fromstring(soap_request)
    except etree.XMLSyntaxError as e:
        raise ValueError("Invalid XML: " + str(e))

    # Validate against DTD
    if not dtd.validate(root):
        raise ValueError("XML does not conform to DTD: " + str(dtd.error_log))

    # Extract the message body
    body = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
    if body is not None:
        return etree.tostring(body, pretty_print=True).decode()
    else:
        raise ValueError("No Body found in SOAP request")